+/// Timing statistics from benchmark runs
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct TimingStats {
+    pub mean_ms: f64,
+    pub median_ms: f64,
+    pub min_ms: f64,
+    pub max_ms: f64,
+    pub run_count: usize,
+}
+
+impl TimingStats {
+    pub fn from_durations(durations: &[Duration]) -> Self {
+        if durations.is_empty() {
+            return Self {
+                mean_ms: 0.0,
+                median_ms: 0.0,
+                min_ms: 0.0,
+                max_ms: 0.0,
+                run_count: 0,
+            };
+        }
+
+        let mut ms_values: Vec<f64> = durations.iter().map(|d| d.as_secs_f64() * 1000.0).collect();
+        ms_values.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
+
+        let n = ms_values.len();
+        let mean = ms_values.iter().sum::<f64>() / n as f64;
+        let median = if n % 2 == 0 {
+            (ms_values[n / 2 - 1] + ms_values[n / 2]) / 2.0
+        } else {
+            ms_values[n / 2]
+        };
+
+        Self {
+            mean_ms: mean,
+            median_ms: median,
+            min_ms: ms_values[0],
+            max_ms: ms_values[n - 1],
+            run_count: n,
+        }
+    }
+}
