+
+fn parse_max_rss_kb(stderr: &str) -> Option<u64> {
+    for line in stderr.lines() {
+        if let Some(rest) = line.strip_prefix("Maximum resident set size (kbytes):") {
+            return rest.trim().parse::<u64>().ok();
+        }
+    }
+    None
+}
